#include <stdio.h>
#include <stdlib.h>

struct Node {
    int val;
    struct Node *left;
    struct Node *right;
};

struct Node* build(int *arr, int l, int r) {
    if (l > r) return NULL;
    int m = l + (r - l) / 2;
    struct Node *node = (struct Node*)malloc(sizeof(struct Node));
    node->val = arr[m];
    node->left = build(arr, l, m - 1);
    node->right = build(arr, m + 1, r);
    return node;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        int *arr = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &arr[i]);
        struct Node *root = build(arr, 0, N - 1);
        (void)root; // tree not used further
        free(arr);
        printf("Successfully created BST!\n");
    }
    return 0;
}

