#include <bits/stdc++.h>
using namespace std;

struct TreeNode {
    int val;
    TreeNode *left, *right;
    TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}
};

TreeNode* build(const vector<int>& a, int l, int r) {
    if (l > r) return nullptr;
    int m = l + (r - l) / 2;
    TreeNode* node = new TreeNode(a[m]);
    node->left = build(a, l, m - 1);
    node->right = build(a, m + 1, r);
    return node;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T;
    if (!(cin >> T)) return 0;
    while (T--) {
        int N; cin >> N;
        vector<int> a(N);
        for (int i = 0; i < N; ++i) cin >> a[i];
        TreeNode* root = build(a, 0, N - 1);
        (void)root; // suppress unused warning
        cout << "Successfully created BST!" << '\n';
    }
    return 0;
}

